import{_ as e,o as a,c as r,a as i}from"./app.9ed7caa4.js";const p=JSON.parse('{"title":"Archive","description":"","frontmatter":{},"headers":[{"level":2,"title":"Archive Sections","slug":"archive-sections","link":"#archive-sections","children":[{"level":3,"title":"Overlay","slug":"overlay","link":"#overlay","children":[]},{"level":3,"title":"Academy","slug":"academy","link":"#academy","children":[]},{"level":3,"title":"Blog / Dev Logs","slug":"blog-dev-logs","link":"#blog-dev-logs","children":[]}]},{"level":2,"title":"Note","slug":"note","link":"#note","children":[]}],"relativePath":"archive/index.md"}'),l={name:"archive/index.md"},t=i('<h1 id="archive" tabindex="-1">Archive <a class="header-anchor" href="#archive" aria-hidden="true">#</a></h1><p>\uC774 \uD398\uC774\uC9C0\uB294 Lyri \xD7 Brian Studio\uC758 \uC774\uC804 \uC2E4\uD5D8, \uAC1C\uBC1C \uAE30\uB85D, \uC624\uBC84\uB808\uC774 \uBB38\uC11C, \uC544\uCE74\uB370\uBBF8 \uC790\uB8CC\uB97C \uBCF4\uAD00\uD558\uB294 \uC544\uCE74\uC774\uBE0C\uC785\uB2C8\uB2E4.</p><p>\uD604\uC7AC \uC0AC\uC774\uD2B8\uC758 \uC911\uC2EC\uC740 \uC74C\uC545, \uC568\uBC94, \uC601\uC0C1 \uC544\uCE74\uC774\uBE0C\uB85C \uC774\uB3D9\uD588\uC9C0\uB9CC,<br> \uAE30\uC874\uC5D0 \uB9CC\uB4E4\uC5C8\uB358 \uBB38\uC11C\uC640 \uAE30\uB85D\uB4E4\uC740 \uC81C\uC791 \uD788\uC2A4\uD1A0\uB9AC\uB85C\uC11C \uADF8\uB300\uB85C \uBCF4\uC874\uD569\uB2C8\uB2E4.</p><h2 id="archive-sections" tabindex="-1">Archive Sections <a class="header-anchor" href="#archive-sections" aria-hidden="true">#</a></h2><h3 id="overlay" tabindex="-1">Overlay <a class="header-anchor" href="#overlay" aria-hidden="true">#</a></h3><p>\uC2E4\uC2DC\uAC04 \uBC29\uC1A1 \uC624\uBC84\uB808\uC774, OBS \uBE0C\uB77C\uC6B0\uC800 \uC18C\uC2A4, \uCC44\uD305 \uC624\uBC84\uB808\uC774, V2/V3 \uAE30\uD68D \uB4F1<br> \uC774\uC804 \uC624\uBC84\uB808\uC774 \uC2E4\uD5D8\uACFC \uAC1C\uBC1C \uBB38\uC11C\uB97C \uBAA8\uC544\uB454 \uC139\uC158\uC785\uB2C8\uB2E4.</p><ul><li><a href="/overlay/">Overlay Docs</a></li></ul><h3 id="academy" tabindex="-1">Academy <a class="header-anchor" href="#academy" aria-hidden="true">#</a></h3><p>\uAC00\uC774\uB4DC, \uC124\uBA85 \uBB38\uC11C, \uD559\uC2B5\uC6A9 \uC815\uB9AC \uC790\uB8CC\uB97C \uBCF4\uAD00\uD558\uB294 \uC139\uC158\uC785\uB2C8\uB2E4.</p><ul><li><a href="/academy/">Academy</a></li></ul><h3 id="blog-dev-logs" tabindex="-1">Blog / Dev Logs <a class="header-anchor" href="#blog-dev-logs" aria-hidden="true">#</a></h3><p>\uD648\uD398\uC774\uC9C0 \uC81C\uC791 \uACFC\uC815, \uC624\uBC84\uB808\uC774 \uAC1C\uBC1C \uB85C\uADF8, \uD2B8\uB7EC\uBE14\uC288\uD305 \uAE30\uB85D \uB4F1<br> \uC774\uC804 \uC791\uC5C5 \uB85C\uADF8\uC640 \uAC1C\uBC1C \uD788\uC2A4\uD1A0\uB9AC\uB97C \uBAA8\uC544\uB454 \uC139\uC158\uC785\uB2C8\uB2E4.</p><ul><li><a href="/blog/">Blog</a></li></ul><h2 id="note" tabindex="-1">Note <a class="header-anchor" href="#note" aria-hidden="true">#</a></h2><p>\uC774 \uC544\uCE74\uC774\uBE0C\uB294 \uD604\uC7AC \uC0AC\uC774\uD2B8\uC758 \uBA54\uC778 \uBC29\uD5A5\uACFC\uB294 \uBCC4\uAC1C\uB85C,<br> Lyri \xD7 Brian Studio\uAC00 \uC5B4\uB5A4 \uC2E4\uD5D8\uACFC \uACFC\uC815\uC744 \uAC70\uCCD0 \uC9C0\uAE08\uC758 \uD615\uD0DC\uC5D0 \uB3C4\uB2EC\uD588\uB294\uC9C0\uB97C \uBCF4\uC5EC\uC8FC\uB294 \uAE30\uB85D \uACF5\uAC04\uC785\uB2C8\uB2E4.</p>',15),d=[t];function c(o,h,n,s,v,_){return a(),r("div",null,d)}const g=e(l,[["render",c]]);export{p as __pageData,g as default};
